package main

import "fmt"

func main() {
    // Append examples
    var s []int
    s = append(s, 10, 20, 30)
    s = append(s, []int{40, 50}...)
    fmt.Println("after append:", s)

    // Copy examples
    a := []int{1, 2, 3, 4, 5}
    b := make([]int, 3)
    copy(b, a[1:])  // copy [2,3,4] into b
    fmt.Println("copy:", b)

    // Copy into specific position
    c := []int{10, 20, 30, 40, 50}
    copy(c[2:], []int{99, 100})
    fmt.Println("in-place copy:", c)
}
